import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);

        response.setContentType("text/html");
        response.getWriter().println("<p>User input: " + sanitizedInput + "</p>");
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization to prevent XSS attacks
        // For example, you can use OWASP Java HTML Sanitizer library

        // Sample sanitization using simple HTML escaping
        return input == null ? "" : input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
